```java
import jakarta.xml.bind.JAXBContext;
import jakarta.xml.bind.Marshaller;
import java.io.File;
import java.io.FileOutputStream;

public class JAXB_Marshall {
    public static void main(String[] args) {
        try {
            // Crear una instancia del contexto JAXB con la clase que tiene anotaciones JAXB
            JAXBContext context = JAXBContext.newInstance(Empleado.class);

            // Crear un marshaller, un objeto que convierte el objeto Java en XML
            Marshaller marshaller = context.createMarshaller();

            // Especificar que la salida debe ser formateada (es decir, "pretty-printed")
            marshaller.setProperty(Marshaller.JAXB_FORMATTED_OUTPUT, Boolean.TRUE);

            // Crear una instancia de tu clase Empleado con los datos que deseas
            Empleado empleado = new Empleado(/* inicializa tu objeto Empleado aquí */);

            // Definir la ruta del archivo XML que se generará
            File file = new File("E:/wservice/empleado.xml");

            // Si el directorio no existe, crearlo
            if (!file.getParentFile().exists()) {
                file.getParentFile().mkdirs();
            }

            // Marshalling del objeto Empleado a un archivo XML
            marshaller.marshal(empleado, new FileOutputStream(file));

            System.out.println("Archivo XML generado con éxito.");
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
```

